use clap::Parser;

#[derive(Parser)]
#[command(name = "{{project}}", about = "A short description")]
struct Cli {
    /// Input value
    input: Option<String>,

    /// Enable verbose output
    #[arg(short, long)]
    verbose: bool,
}

fn main() {
    let cli = Cli::parse();
    if cli.verbose {
        eprintln!("verbose mode on");
    }
    println!("Hello from {{project}}: {:?}", cli.input);
}
